'use client';

import React, { memo } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { useGlobal } from '@/context/GlobalContext';

// Sabit stil objeleri — her render'da yeni referans oluşturulmasını önler
const MONOGRAM_FONT_STYLE = { fontFamily: '"Cormorant Garamond", serif' } as const;
const SITE_NAME_STYLE = {
    fontFamily: '"Cormorant Garamond", serif',
    fontSize: '24px',
    fontWeight: 500,
    letterSpacing: '0.2em',
    lineHeight: 1.2,
    textTransform: 'uppercase' as const,
} as const;
const SLOGAN_STYLE = {
    fontFamily: '"Inter", sans-serif',
    fontSize: '9px',
    fontWeight: 400,
    letterSpacing: '0.4em',
    color: '#C9A96E',
    textTransform: 'uppercase' as const,
} as const;
const CAPSULE_NAME_STYLE = {
    fontFamily: '"Cormorant Garamond", serif',
    whiteSpace: 'nowrap' as const,
} as const;
const LINK_STYLE = { textDecoration: 'none' } as const;

// Animasyon varyantları — inline obje oluşturmayı önler
const CAPSULE_TEXT_VARIANTS = {
    hidden: { opacity: 0, x: -15 },
    visible: { opacity: 1, x: 0 },
} as const;
const BELOW_LOGO_VARIANTS = {
    hidden: { opacity: 0, y: 10, scale: 0.95 },
    visible: { opacity: 1, y: 0, scale: 1 },
} as const;
const CAPSULE_TEXT_TRANSITION = { duration: 0.4, ease: 'easeOut' } as const;

const DEFAULT_SLOGAN = 'HOME CONCEPT';

interface NavbarLogoProps {
    isScrolled: boolean;
    isMobileMenuOpen?: boolean;
}

export const NavbarLogo = memo(function NavbarLogo({ isScrolled }: NavbarLogoProps) {
    const { siteSettings, t } = useGlobal();
    const [mounted, setMounted] = React.useState(false);
    React.useEffect(() => setMounted(true), []);

    const pathname = usePathname();

    // siteName: SSR sırasında da güvenli — siteSettings henüz yoksa fallback kullan
    const siteName = siteSettings?.site_info?.siteName || 'SELIS';

    // siteSlogan: mounted kontrolü ile hydration mismatch önlenir
    // SSR ve ilk client render'da aynı değer ("HOME CONCEPT") döner
    const siteSlogan = React.useMemo(() => {
        if (!mounted) return DEFAULT_SLOGAN;
        const raw = siteSettings?.site_info?.siteSlogan || '';
        if (raw && raw !== 'SİTE SLOGAN') return raw;
        const translated = t('site_slogan');
        if (translated && translated !== 'site_slogan') return translated;
        return DEFAULT_SLOGAN;
    }, [mounted, siteSettings?.site_info?.siteSlogan, t]);

    const handleClick = React.useCallback((e: React.MouseEvent) => {
        if (pathname === '/') {
            e.preventDefault();
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    }, [pathname]);

    return (
        <Link
            href="/"
            prefetch={true}
            onClick={handleClick}
            className="flex flex-col items-center justify-center group pointer-events-auto"
            style={LINK_STYLE}
            aria-label="SELIS Anasayfa"
        >
            <motion.div
                layout
                className={`relative flex flex-col items-center transition-all duration-500 ${isScrolled ? 'gap-0' : 'gap-4'}`}
            >
                {/* Logo Container - Transforms between Circle and Capsule */}
                <motion.div
                    layout
                    className={`
                        relative flex items-center justify-center overflow-hidden transition-all duration-500 shadow-sm
                        border border-[#E5D5BC] dark:border-white/10
                        ${isScrolled
                            ? 'w-max min-w-fit h-12 rounded-full px-6 bg-[#FCFBF7]/95 dark:bg-zinc-950/95 backdrop-blur-md shadow-lg shadow-black/5'
                            : 'w-14 h-14 rounded-full bg-white dark:bg-zinc-900'
                        }
                    `}
                >
                    <div className="flex items-center gap-4 w-max">
                        {/* Monogram "S" */}
                        <motion.span
                            layout
                            className={`font-serif italic transition-colors duration-500 leading-none shrink-0
                                ${isScrolled ? 'text-[#C9A96E] text-xl' : 'text-[#4A4A4A] dark:text-white text-2xl'}
                            `}
                            style={MONOGRAM_FONT_STYLE}
                        >
                            S
                        </motion.span>

                        {/* Scrolled: Content inside the capsule */}
                        <AnimatePresence mode="wait">
                            {isScrolled && (
                                <motion.div
                                    key="capsule-name"
                                    variants={CAPSULE_TEXT_VARIANTS}
                                    initial="hidden"
                                    animate="visible"
                                    exit="hidden"
                                    transition={CAPSULE_TEXT_TRANSITION}
                                    className="flex flex-col items-start justify-center ml-1"
                                >
                                    <span
                                        className="text-[#1A1A1A] dark:text-white uppercase font-serif tracking-[0.15em] text-[13px] font-semibold whitespace-nowrap"
                                        style={CAPSULE_NAME_STYLE}
                                    >
                                        {siteName}
                                    </span>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                </motion.div>

                {/* Not Scrolled: Content below the circle */}
                <AnimatePresence>
                    {!isScrolled && (
                        <motion.div
                            key="below-logo"
                            variants={BELOW_LOGO_VARIANTS}
                            initial="hidden"
                            animate="visible"
                            exit="hidden"
                            className="flex flex-col items-center text-center px-4"
                        >
                            <span
                                className="block text-[#1A1A1A] dark:text-white"
                                style={SITE_NAME_STYLE}
                            >
                                {siteName}
                            </span>

                            <div className="flex items-center gap-2 mt-1.5 opacity-90">
                                <div className="hidden sm:block h-px w-4 bg-[#C9A96E]/50" />
                                <span style={SLOGAN_STYLE}>
                                    {siteSlogan}
                                </span>
                                <div className="hidden sm:block h-px w-4 bg-[#C9A96E]/50" />
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </motion.div>
        </Link>
    );
});
