'use client';

import * as React from 'react';
import { supabase } from '@/lib/supabase';
import type { NavCategory } from './navbar.types';

// URL → translation key mapping for Supabase menu items that don't match NAV_CATEGORIES
const URL_DATAKEY_MAP: Record<string, string> = {
    '/urunler': 'nav_products',
    '/koleksiyonlar': 'nav_collections',
    '/lookbook': 'nav_lookbook',
    '/hakkimizda': 'nav_about',
    '/iletisim': 'nav_contact',
    '/blog': 'nav_inspiration',
    '/kampanyalar': 'nav_campaigns',
    '/kategori/oturma-odasi': 'nav_living_room',
    '/kategori/yatak-odasi': 'nav_bedroom',
    '/kategori/yemek-odasi': 'nav_dining',
    '/kategori/calisma-odasi': 'nav_office',
    '/kategori/aydinlatma': 'nav_lighting',
    '/kategori/dekorasyon': 'nav_decoration',
};

export function useHeaderMenu(initialCategories: NavCategory[]) {
    const [dynamicCategories, setDynamicCategories] = React.useState<NavCategory[]>(initialCategories);

    React.useEffect(() => {
        const fetchHeaderMenu = async () => {
            try {
                // Find 'header' menu
                const { data: menu, error: menuError } = await supabase
                    .from('menus')
                    .select('id, name')
                    .eq('handle', 'header')
                    .single();

                if (menuError) {
                    if (menuError.code !== 'PGRST116') { // Ignore "no rows found" error
                        console.warn("Header menu not found in Supabase, using static fallback", menuError);
                    }
                    // If menu is not found or there's an error, we stop here and keep initialCategories
                    return;
                }

                if (menu) {
                    const { data: items, error: itemsError } = await supabase
                        .from('menu_items')
                        .select('*')
                        .eq('menu_id', menu.id)
                        .eq('is_active', true)
                        .order('sort_order', { ascending: true });

                    if (itemsError) {
                        console.warn("Error loading header menu items", itemsError);
                        return;
                    }

                    if (items && items.length > 0) {
                        const newCategories = items.map((item: any) => {
                            const existing = initialCategories.find(c => c.href === item.url || c.label.toLowerCase() === item.title.toLowerCase());
                            return {
                                id: item.id,
                                label: item.title,
                                href: item.url,
                                dataKey: existing?.dataKey || URL_DATAKEY_MAP[item.url] || '',
                                subCategories: existing?.subCategories ?? [],
                                featuredProduct: existing?.featuredProduct ?? null,
                                editorialText: existing?.editorialText,
                                editorialTextKey: existing?.editorialTextKey,
                                promotionText: existing?.promotionText,
                                promotionTextKey: existing?.promotionTextKey,
                            };
                        });

                        // Only override if Supabase menu is complete (has at least as many items as static)
                        // AND has rich mega-menu data. A partial Supabase menu (e.g. only 4 items vs 9 static)
                        // must not replace the full static menu.
                        const hasRichData = newCategories.some((c: NavCategory) => c.subCategories && c.subCategories.length > 0);
                        const isComplete = newCategories.length >= initialCategories.length;
                        if (hasRichData && isComplete) {
                            setDynamicCategories(newCategories as NavCategory[]);
                        }
                    }
                }
            } catch (error) {
                console.warn("Failed to load dynamic header menu:", error);
            }
        };

        fetchHeaderMenu();
    }, [initialCategories]);

    return { dynamicCategories };
}
