'use client';

import { useState, useEffect, useCallback } from 'react';
import { NOTIFICATION_POOL } from './socialProof.data';
import type { LiveNotificationData, RealtimeNotificationData } from './socialProof.data';

interface NotificationState {
    current: LiveNotificationData | null;
    isVisible: boolean;
}

export function useNotifications(
    intervalMs = 8000, // kaç ms'de bir yeni bildirim
    displayMs = 5000 // bildirim kaç ms görünür
) {
    const [state, setState] = useState<NotificationState>({
        current: null,
        isVisible: false,
    });
    const [pool, setPool] = useState<LiveNotificationData[]>([]);
    const [index, setIndex] = useState(0);
    const [isDismissed, setIsDismissed] = useState(false);

    const showNext = useCallback(
        (currentIndex: number, currentPool: LiveNotificationData[]) => {
            if (isDismissed || currentPool.length === 0) return;

            const next = currentPool[currentIndex % currentPool.length];
            setState({ current: next, isVisible: true });

            // displayMs sonra gizle
            setTimeout(() => {
                setState((prev) => ({ ...prev, isVisible: false }));
            }, displayMs);

            setIndex(currentIndex + 1);
        },
        [isDismissed, displayMs]
    );

    const dismiss = useCallback(() => {
        setIsDismissed(true);
        setState({ current: null, isVisible: false });
    }, []);

    useEffect(() => {
        let isMounted = true;
        let currentIndex = 0;
        let intervalId: NodeJS.Timeout;
        let firstTimer: NodeJS.Timeout;

        const initNotifications = async () => {
            try {
                const res = await fetch('/api/recent-purchases');
                const data = await res.json();
                
                let currentPool = NOTIFICATION_POOL;
                
                if (data?.notifications && data.notifications.length > 0) {
                    currentPool = data.notifications.map((n: RealtimeNotificationData) => {
                        // Calculate time ago
                        const orderDate = new Date(n.createdAt);
                        const now = new Date();
                        const diffMs = now.getTime() - orderDate.getTime();
                        const diffMins = Math.floor(diffMs / (1000 * 60));
                        
                        let timeAgoText = '';
                        if (diffMins < 60) {
                            timeAgoText = `${diffMins} dk önce`;
                        } else if (diffMins < 24 * 60) {
                            timeAgoText = `${Math.floor(diffMins / 60)} saat önce`;
                        } else {
                            timeAgoText = `${Math.floor(diffMins / (24 * 60))} gün önce`;
                        }
                        
                        return {
                            ...n,
                            minutesAgo: diffMins, // fallback
                            timeAgoText,
                        };
                    });
                }
                
                if (!isMounted) return;
                
                setPool(currentPool);

                // 3 saniye sonra ilkini göster
                firstTimer = setTimeout(() => {
                    if (isMounted) {
                        showNext(currentIndex, currentPool);
                        currentIndex++;
                    }
                }, 3000);

                // Sonra intervalMs'de bir tekrarla
                intervalId = setInterval(() => {
                    if (isMounted) {
                        showNext(currentIndex, currentPool);
                        currentIndex++;
                    }
                }, intervalMs + displayMs);
            } catch (error) {
                console.warn('Failed to fetch notifications:', error);
                
                if (!isMounted) return;
                
                const currentPool = NOTIFICATION_POOL;
                setPool(currentPool);
                
                firstTimer = setTimeout(() => {
                    if (isMounted) {
                        showNext(currentIndex, currentPool);
                        currentIndex++;
                    }
                }, 3000);

                intervalId = setInterval(() => {
                    if (isMounted) {
                        showNext(currentIndex, currentPool);
                        currentIndex++;
                    }
                }, intervalMs + displayMs);
            }
        };

        initNotifications();

        return () => {
            isMounted = false;
            if (firstTimer) clearTimeout(firstTimer);
            if (intervalId) clearInterval(intervalId);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []); // sadece mount'ta çalışsın

    return { ...state, dismiss };
}
