'use client';

import { useState } from 'react';
import { createSupabaseBrowserClient } from '@/lib/supabase-browser';
import { useTranslationStore, translations } from '@/store/translationStore';

export function SocialLogin() {
    const { language } = useTranslationStore();
    const t = (key: string) => translations[language]?.[key];
    const [loading, setLoading] = useState<'google' | null>(null);

    const handleOAuth = async (provider: 'google') => {
        setLoading(provider);
        const supabase = createSupabaseBrowserClient();
        await supabase.auth.signInWithOAuth({
            provider,
            options: {
                redirectTo: `${window.location.origin}/auth/callback`,
            },
        });
        setLoading(null);
    };

    return (
        <div className="flex flex-col gap-3 px-8 pt-6">
            <button
                onClick={() => handleOAuth('google')}
                disabled={loading !== null}
                className="w-full py-3 flex items-center justify-center gap-3 relative transition-opacity hover:opacity-80 disabled:opacity-60 disabled:cursor-not-allowed"
                style={{ border: '1px solid #E0E0E0', borderRadius: '6px', background: 'white' }}
            >
                {loading === 'google' ? (
                    <span className="w-5 h-5 border-2 border-gray-300 border-t-gray-600 rounded-full animate-spin" />
                ) : (
                    <svg width="20" height="20" viewBox="0 0 24 24">
                        <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4" />
                        <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                        <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                        <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                    </svg>
                )}
                <span className="text-[13px] font-medium" style={{ color: '#1C1C1E' }}>
                    {t('auth_btn_google') || 'Google ile Devam Et'}
                </span>
            </button>

        </div>
    );
}
